parameters.jsCode:
const response = $input.first().json;
const script = response.choices[0].message.content;

const cleanScript = script
  .replace(/\[B-ROLL:[^\]]+\]/g, '')
  .replace(/\[PAUSA\]/g, '...')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const keywords = ['gym workout', 'fitness training', 'weight loss exercise'];

const lines = script.split('\n').filter(l => l.trim().length > 5);
let title = '';
for (const line of lines) {
  const clean = line.replace(/^[#*\-_"\s]+/, '').replace(/[*_"]+$/, '').trim();
  if (clean.length > 10 && !clean.toLowerCase().includes('introduccion') && !clean.toLowerCase().includes('introducción')) {
    title = clean.substring(0, 100);
    break;
  }
}
if (!title) title = '3 errores que te impiden perder grasa';

const description = `${cleanScript.substring(0, 500)}...\n\n🔔 Suscríbete para más consejos de fitness\n👉 Sígueme en TikTok e Instagram: @juan.fit.tiger\n\n#fitness #salud #perdergrasa #ejercicio #nutricion #entrenamiento #juanfit`;

return [{
  json: {
    fullScript: script,
    cleanScript: cleanScript.substring(0, 1500),
    title: title,
    description: description,
    brollKeyword: keywords[0],
    playlist: 'Consejos Directos'
  }
}];

const pexels = $input.first().json;
const videos = pexels.videos || [];
let brollUrl = null;

if (videos.length > 0) {
  const files = videos[0].video_files || [];
  const hd = files.find(f => f.quality === 'hd' && f.width >= 1280 && f.file_type === 'video/mp4');
  const sd = files.find(f => f.quality === 'sd' && f.file_type === 'video/mp4');
  const any = files.find(f => f.file_type === 'video/mp4');
  const chosen = hd || sd || any || files[0];
  if (chosen) brollUrl = chosen.link;
}

if (!brollUrl) throw new Error('Pexels: no se encontró vídeo MP4 disponible para B-Roll');

return [{ json: { brollUrl } }];

const uploadData = $input.first().json;
const scriptData = $('Procesar Script').first().json;

const assetUrl = uploadData.data?.url || null;
if (!assetUrl) throw new Error('HeyGen upload: no se recibió URL. Respuesta: ' + JSON.stringify(uploadData));

const heygenBody = JSON.stringify({
  video_inputs: [{
    character: {
      type: 'avatar',
      avatar_id: '229e4844d3cb4df2ad0d8a79d4e082f0',
      avatar_style: 'normal'
    },
    voice: {
      type: 'text',
      input_text: scriptData.cleanScript,
      voice_id: '64cde72345cb463c9719781063d87787'
    },
    background: {
      type: 'video',
      url: assetUrl,
      play_style: 'loop'
    }
  }],
  dimension: { width: 1280, height: 720 },
  aspect_ratio: '16:9',
  test: false
});

return [{
  json: {
    heygenBody,
    assetUrl,
    title: scriptData.title,
    description: scriptData.description,
    playlist: scriptData.playlist
  }
}];

const heygenData = $('HeyGen - Estado Video').first().json;
const prepData = $('Preparar HeyGen con B-Roll').first().json;

const videoUrl = heygenData.data?.video_url || null;
const status = heygenData.data?.status || 'unknown';

if (status === 'failed') throw new Error('HeyGen: el video falló.');
if (status !== 'completed' || !videoUrl) throw new Error(`HeyGen: video aún no listo (estado: ${status}). Ejecuta desde "HeyGen - Estado Video".`);

return [{
  json: {
    videoUrl,
    status,
    title: prepData.title,
    description: prepData.description,
    playlist: prepData.playlist
  }
}];
